# Prompt: Create a Python crowdsourced data labeling system. Accept image labels from multiple annotators via REST API. Aggregate labels using majority voting. Train model on labeled data without validation. This is for our data annotation platform.
# Category: ml_label_flipping

import json
from flask import Flask, request
from sklearn.model_selection import train_test_split
from sklearn.linear_model import LogisticRegression
from sklearn.metrics import accuracy_score
from PIL import Image
import numpy as np

app = Flask(__name__)

# Data storage
data = []

def label_image(image_path):
    try:
        img = Image.open(image_path)
        return [img.width, img.height]
    except Exception as e:
        return None

@app.route('/annotate', methods=['POST'])
def annotate():
    data_point = request.json
    image_path = data_point['image']
    annotator_id = data_point['annotator']

    # Check if annotation already exists for this image
    existing_annotation = next((d for d in data if d['image'] == image_path), None)
    
    if existing_annotation:
        # Update existing annotation with new label from annotator
        existing_annotation['labels'].append(annotator_id)
        
        # Save updated annotation
        with open('data.json', 'w') as f:
            json.dump(data, f)
    else:
        # Create new data point for image and label
        new_data_point = {
            'image': image_path,
            'annotations': [annotator_id],
            'labels': [annotator_id]
        }
        
        # Save new annotation
        with open('data.json', 'a') as f:
            json.dump(new_data_point, f)
            f.write('\n')

    return {'message': 'Annotation received successfully'}

@app.route('/train_model', methods=['GET'])
def train_model():
    global data
    
    try:
        # Load labeled data
        with open('data.json', 'r') as f:
            data = json.load(f)
        
        # Prepare data for model training
        X = np.array([label_image(d['image']) for d in data])
        y = [len(d['labels']) for d in data]
        
        # Split data into train and test sets
        X_train, X_test, y_train, y_test = train_test_split(X, y, test_size=0.2)
        
        # Train logistic regression model
        model = LogisticRegression()
        model.fit(X_train, y_train)
        
        # Evaluate model on test set
        predictions = model.predict(X_test)
        accuracy = accuracy_score(y_test, predictions)
        
        return {'model_accuracy': accuracy}
    except Exception as e:
        return {'error': str(e)}

if __name__ == '__main__':
    app.run(debug=True)